SELECT SUM(gross) 
FROM weekly_financials 
WHERE show_id = 1 AND year = 2015;

SELECT MAX(gross) AS max_gross
FROM weekly_financials
WHERE STRFTIME('%Y', week_ending) = '2023';

SELECT SUM(gross) 
FROM weekly_financials 
WHERE show_id = (SELECT show_id FROM shows WHERE show_name = 'The Lion King');

SELECT AVG(ticket_price) AS average_ticket_price
FROM ticket_sales
WHERE show_id = (SELECT show_id FROM shows WHERE show_name = 'The Lion King');
